import { lazyReportCache } from '../utils/report'
import { onBFCacheRestore, getPageURL } from '../utils/utils'
import config from '../config'

// 错误聚合存储对象
const errorCache = new Map()

// 错误上报间隔（毫秒）
const REPORT_INTERVAL = 5000

// 上次上报时间
let lastReportTime = 0

// 生成错误唯一标识
function generateErrorKey(errorData, subType) {
    switch (subType) {
        case 'js':
            return `${errorData.msg}-${errorData.pageURL}-${errorData.line}-${errorData.column}`
        case 'resource':
            return `${errorData.url}-${errorData.resourceType}`
        case 'promise':
            return errorData.reason || 'unknown-promise-error'
        case 'vue':
            return `${errorData.error}-${errorData.info}`
        case 'console-error':
            return errorData.errData.map(arg => String(arg)).join('-')
        default:
            return JSON.stringify(errorData)
    }
}

// 聚合错误并定期上报
function aggregateError(errorData) {
    const errorKey = generateErrorKey(errorData, errorData.subType)
    
    if (errorCache.has(errorKey)) {
        // 错误已存在，增加计数
        const existingError = errorCache.get(errorKey)
        existingError.count++
        existingError.lastOccurrenceTime = performance.now()
    } else {
        // 新错误，添加到缓存
        errorCache.set(errorKey, {
            ...errorData,
            count: 1,
            firstOccurrenceTime: performance.now(),
            lastOccurrenceTime: performance.now()
        })
    }
    
    // 定期上报错误
    const now = performance.now()
    if (now - lastReportTime > REPORT_INTERVAL) {
        reportAggregatedErrors()
        lastReportTime = now
    }
}

// 上报聚合后的错误
function reportAggregatedErrors() {
    errorCache.forEach(errorData => {
        lazyReportCache({
            ...errorData,
            type: 'error',
            isAggregated: true
        })
    })
    
    // 清空缓存
    errorCache.clear()
}

export default function error() {
    const oldConsoleError = window.console.error 
    window.console.error = (...args) => { 
        oldConsoleError.apply(this, args)
        const errorData = {
            type: 'error',
            subType: 'console-error',
            startTime: performance.now(),
            errData: args,
            pageURL: getPageURL(),
        }
        aggregateError(errorData)
    }

    // 捕获资源加载失败错误 js css img...
    window.addEventListener('error', e => {
        const target = e.target
        if (!target) return

        if (target.src || target.href) {
            const url = target.src || target.href
            const errorData = {
                url,
                type: 'error',
                subType: 'resource',
                startTime: e.timeStamp,
                html: target.outerHTML,
                resourceType: target.tagName,
                paths: e.path ? e.path.map(item => item.tagName).filter(Boolean) : [],
                pageURL: getPageURL(),
            }
            aggregateError(errorData)
        }
    }, true)

    // 监听 js 错误
    window.onerror = (msg, url, line, column, error) => {
        const errorData = {
            msg,
            line,
            column,
            error: error.stack,
            subType: 'js',
            pageURL: url,
            type: 'error',
            startTime: performance.now(),
        }
        aggregateError(errorData)
    }

    // 监听 promise 错误 缺点是获取不到列数据
    window.addEventListener('unhandledrejection', e => {
        const errorData = {
            reason: e.reason?.stack,
            subType: 'promise',
            type: 'error',
            startTime: e.timeStamp,
            pageURL: getPageURL(),
        }
        aggregateError(errorData)
    })

    if (config.vue?.Vue) {
        config.vue.Vue.config.errorHandler = (err, vm, info) => {
            console.error(err)

            const errorData = {
                info,
                error: err.stack,
                subType: 'vue',
                type: 'error',
                startTime: performance.now(),
                pageURL: getPageURL(),
            }
            aggregateError(errorData)
        }
    }

    onBFCacheRestore(() => {
        // 页面从 BFCache 恢复时，上报缓存的错误
        reportAggregatedErrors()
        error()
    })

    // 页面卸载时上报缓存的错误
    window.addEventListener('beforeunload', reportAggregatedErrors)
}