import { originalOpen, originalSend } from './xhr'
import { addCache, getCache, clearCache } from './cache'
import { getFingerprint, getSessionId } from './utils'
import config from '../config'

export function isSupportSendBeacon() {
    return !!window.navigator?.sendBeacon
}

// 上报队列
const reportQueue = []
// 队列处理状态
let isProcessing = false
// 最大重试次数
const MAX_RETRY = 3
// 批量上报间隔
const BATCH_INTERVAL = 2000
// 批量上报大小
const BATCH_SIZE = 10

// 检查网络状态
function isOnline() {
    return navigator.onLine
}

// 采样率控制
function shouldSample() {
    return Math.random() < config.sampleRate
}

// 生成会话 ID
const sessionID = getSessionId()
// 获取用户唯一标识
const fingerprint = getFingerprint()

// 上报数据
function doReport(data, retryCount = 0) {
    if (!config.url) {
        console.error('请设置上传 url 地址')
        return Promise.reject(new Error('请设置上传 url 地址'))
    }

    const reportData = {
        id: sessionID,
        appID: config.appID,
        userID: config.userID || fingerprint,
        fingerprint,
        sessionID,
        data,
        timestamp: Date.now()
    }

    const jsonData = JSON.stringify(reportData)

    return new Promise((resolve, reject) => {
        // 尝试使用 sendBeacon
        if (isSupportSendBeacon() && !isImmediate) {
            const success = navigator.sendBeacon(config.url, jsonData)
            if (success) {
                resolve()
                return
            }
        }

        // 降级到 XHR
        const xhr = new XMLHttpRequest()
        xhr.open('POST', config.url, true)
        xhr.setRequestHeader('Content-Type', 'application/json')
        
        xhr.onload = function() {
            if (xhr.status >= 200 && xhr.status < 300) {
                resolve()
            } else {
                handleRetry(data, retryCount, reject)
            }
        }
        
        xhr.onerror = function() {
            handleRetry(data, retryCount, reject)
        }
        
        xhr.send(jsonData)
    })
}

// 处理重试
function handleRetry(data, retryCount, reject) {
    if (retryCount < MAX_RETRY) {
        // 指数退避重试
        const delay = Math.pow(2, retryCount) * 1000
        setTimeout(() => {
            doReport(data, retryCount + 1)
        }, delay)
    } else {
        // 达到最大重试次数，存储到离线缓存
        storeOfflineData(data)
        reject(new Error('上报失败，已存储到离线缓存'))
    }
}

// 存储离线数据
function storeOfflineData(data) {
    try {
        const offlineKey = 'monitor_offline_data'
        const offlineData = JSON.parse(localStorage.getItem(offlineKey) || '[]')
        offlineData.push(...(Array.isArray(data) ? data : [data]))
        // 限制离线数据大小
        if (offlineData.length > 100) {
            offlineData.splice(0, offlineData.length - 100)
        }
        localStorage.setItem(offlineKey, JSON.stringify(offlineData))
    } catch (e) {
        // 忽略存储错误
    }
}

// 处理离线数据
function processOfflineData() {
    if (!isOnline()) return

    try {
        const offlineKey = 'monitor_offline_data'
        const offlineData = JSON.parse(localStorage.getItem(offlineKey) || '[]')
        if (offlineData.length > 0) {
            // 批量处理离线数据
            const batchData = offlineData.splice(0, BATCH_SIZE)
            doReport(batchData).then(() => {
                // 处理成功，更新离线数据
                localStorage.setItem(offlineKey, JSON.stringify(offlineData))
                // 继续处理剩余数据
                if (offlineData.length > 0) {
                    setTimeout(processOfflineData, 1000)
                }
            })
        }
    } catch (e) {
        // 忽略处理错误
    }
}

// 处理上报队列
function processQueue() {
    if (isProcessing || reportQueue.length === 0) return

    isProcessing = true

    // 批量处理队列数据
    const batchData = reportQueue.splice(0, BATCH_SIZE)

    doReport(batchData).then(() => {
        isProcessing = false
        // 继续处理队列
        if (reportQueue.length > 0) {
            processQueue()
        }
    }).catch(() => {
        isProcessing = false
    })
}

// 定时处理队列
setInterval(() => {
    if (reportQueue.length > 0) {
        processQueue()
    }
}, BATCH_INTERVAL)

// 监听网络状态变化
window.addEventListener('online', processOfflineData)

// 初始处理离线数据
setTimeout(processOfflineData, 1000)

export function report(data, isImmediate = false) {
    // 采样率控制
    if (!shouldSample()) {
        return
    }

    if (isImmediate) {
        // 立即上报
        doReport(data)
    } else {
        // 加入队列
        if (Array.isArray(data)) {
            reportQueue.push(...data)
        } else {
            reportQueue.push(data)
        }
        // 触发队列处理
        processQueue()
    }
}

let timer = null
export function lazyReportCache(data, timeout = 3000) {
    // 采样率控制
    if (!shouldSample()) {
        return
    }

    addCache(data)

    clearTimeout(timer)
    timer = setTimeout(() => {
        const data = getCache()
        if (data.length) {
            report(data)
            clearCache()
        }
    }, timeout)
}

export function reportWithXHR(data) {
    const xhr = new XMLHttpRequest()
    originalOpen.call(xhr, 'post', config.url)
    xhr.setRequestHeader('Content-Type', 'application/json')
    originalSend.call(xhr, JSON.stringify(data))
}