export function deepCopy(target) {
    if (typeof target === 'object') {
        const result = Array.isArray(target) ? [] : {}
        for (const key in target) {
            if (typeof target[key] == 'object') {
                result[key] = deepCopy(target[key])
            } else {
                result[key] = target[key]
            }
        }

        return result
    }

    return target
}

export function onBFCacheRestore(callback) {
    window.addEventListener('pageshow', event => {
        if (event.persisted) {
            callback(event)
        }
    }, true)
}

export function onBeforeunload(callback) {
    window.addEventListener('beforeunload', callback, true)
}

export function onHidden(callback, once) {
    const onHiddenOrPageHide = (event) => {
        if (event.type === 'pagehide' || document.visibilityState === 'hidden') {
            callback(event)
            if (once) {
                window.removeEventListener('visibilitychange', onHiddenOrPageHide, true)
                window.removeEventListener('pagehide', onHiddenOrPageHide, true)
            }
        }
    }

    window.addEventListener('visibilitychange', onHiddenOrPageHide, true)
    window.addEventListener('pagehide', onHiddenOrPageHide, true)
}

export function executeAfterLoad(callback) {
    if (document.readyState === 'complete') {
        callback()
    } else {
        const onLoad = () => {
            callback()
            window.removeEventListener('load', onLoad, true)
        }

        window.addEventListener('load', onLoad, true)
    }
}

export function getPageURL() {
    return window.location.href 
}

// 生成用户唯一标识（Fingerprint）
export function getFingerprint() {
    const STORAGE_KEY = 'monitor_fingerprint'
    
    // 尝试从 localStorage 获取
    let fingerprint = localStorage.getItem(STORAGE_KEY)
    if (fingerprint) {
        return fingerprint
    }
    
    // 生成新的指纹
    const canvas = document.createElement('canvas')
    const ctx = canvas.getContext('2d')
    ctx.fillStyle = 'rgb(255, 255, 255)'
    ctx.fillRect(0, 0, 200, 200)
    ctx.fillStyle = 'rgb(0, 0, 0)'
    ctx.font = '14px Arial'
    ctx.fillText('browser fingerprint', 10, 20)
    
    const canvasHash = canvas.toDataURL('image/jpeg').hashCode()
    const userAgentHash = navigator.userAgent.hashCode()
    const screenHash = (screen.width * screen.height * screen.colorDepth).toString().hashCode()
    
    fingerprint = `${canvasHash}-${userAgentHash}-${screenHash}-${Date.now()}`
    
    // 存储到 localStorage
    try {
        localStorage.setItem(STORAGE_KEY, fingerprint)
    } catch (e) {
        // 忽略存储错误
    }
    
    return fingerprint
}

// 字符串哈希函数
String.prototype.hashCode = function() {
    let hash = 0
    for (let i = 0; i < this.length; i++) {
        const char = this.charCodeAt(i)
        hash = ((hash << 5) - hash) + char
        hash = hash & hash // 转换为 32 位整数
    }
    return Math.abs(hash)
}

// 生成会话 ID
export function getSessionId() {
    const STORAGE_KEY = 'monitor_session_id'
    const SESSION_TIMEOUT = 30 * 60 * 1000 // 30分钟会话超时
    
    // 尝试从 localStorage 获取
    const sessionData = localStorage.getItem(STORAGE_KEY)
    if (sessionData) {
        try {
            const { sessionId, timestamp } = JSON.parse(sessionData)
            // 检查会话是否超时
            if (Date.now() - timestamp < SESSION_TIMEOUT) {
                // 更新会话时间戳
                localStorage.setItem(STORAGE_KEY, JSON.stringify({ sessionId, timestamp: Date.now() }))
                return sessionId
            }
        } catch (e) {
            // 解析错误，创建新会话
        }
    }
    
    // 生成新的会话 ID
    const sessionId = `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
    
    // 存储到 localStorage
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify({ sessionId, timestamp: Date.now() }))
    } catch (e) {
        // 忽略存储错误
    }
    
    return sessionId
}

// 监听页面可见性变化
export function onVisibilityChange(callback) {
    if (typeof document.hidden !== 'undefined') {
        document.addEventListener('visibilitychange', callback, true)
    } else if (typeof document.msHidden !== 'undefined') {
        document.addEventListener('msvisibilitychange', callback, true)
    } else if (typeof document.webkitHidden !== 'undefined') {
        document.addEventListener('webkitvisibilitychange', callback, true)
    }
}

// 监听页面显示
export function onShown(callback) {
    onVisibilityChange(() => {
        if (!document.hidden) {
            callback()
        }
    })
}